"use strict";(self.webpackChunkjose_trejos_portfolio=self.webpackChunkjose_trejos_portfolio||[]).push([["607"],{7735(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"building-my-portfolio","metadata":{"permalink":"/blog/building-my-portfolio","editUrl":"https://github.com/jtrejos506/jose-trejos-portfolio/blog/2026-03-12-building-my-portfolio.mdx","source":"@site/blog/2026-03-12-building-my-portfolio.mdx","title":"Building My Portfolio","description":"This site started as a simple idea: document what I know. It\u2019s evolving into something more useful, a structured portfolio that reflects how I approach real problems in DevOps, Linux, and observability.","date":"2026-03-12T00:00:00.000Z","tags":[{"inline":false,"label":"Learning","permalink":"/blog/tags/learning","description":"Notes, lessons, and knowledge gained."}],"readingTime":0.94,"hasTruncateMarker":false,"authors":[{"name":"Jose Trejos","title":"Technical Lead & Operations Manager","url":"https://josetrejos.com","page":{"permalink":"/blog/authors/jtrejos"},"socials":{"linkedin":"https://www.linkedin.com/in/jose-506/","github":"https://github.com/jtrejos506"},"imageURL":"https://github.com/jtrejos506.png","key":"jtrejos"}],"frontMatter":{"slug":"building-my-portfolio","title":"Building My Portfolio","authors":["jtrejos"],"tags":["learning"]},"unlisted":false},"content":"This site started as a simple idea: document what I know. It\u2019s evolving into something more useful, a structured portfolio that reflects how I approach real problems in DevOps, Linux, and observability.\\n\\nInstead of treating this as a traditional blog, I\u2019m combining two things:\\n\\n- Projects (Docs): Clear, structured case studies of what I\u2019ve built\\n- Blog: Short posts focused on lessons, decisions, and learning along the way\\n\\n## Why this approach?\\n\\nIn many portfolios, projects exist without context, and blogs exist without proof of execution. I want both:\\n\\n- Show what I built\\n- Explain how I think\\n\\n## What you can expect\\n\\nGoing forward, I\u2019ll be sharing:\\n\\n- Practical implementations (Linux, automation, etc)\\n- Troubleshooting scenarios and solutions\\n- Small experiments and lab setups\\n- Lessons learned from real or simulated projects\\n\\n## A note on client work\\n\\nSome projects are based on real-world experience but are anonymized to respect confidentiality. The focus is always on the technical challenge and solution.\\n\\n## What\u2019s next\\n\\nThe next posts will dive into:\\n\\n- Building a basic logging pipeline\\n- Structuring a clean project case study\\n- Setting up reproducible DevOps labs\\n\\n---\\n\\nThis is a work in progress\u2014but that\u2019s the point."}]}}')}}]);